import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('validateOrderItems', () => {
    it('should pass for non-empty items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });

    it('should pass for multiple items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
        ]),
      ).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('delivered', 'shipped')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'shipped')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'delivered')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { isInQuietHours } from '../../src/validators/preferences.validator.js';

describe('Preferences Validators', () => {
  describe('isInQuietHours', () => {
    describe('simple range (no wrap-around)', () => {
      it('should return true when hour is within range', () => {
        expect(isInQuietHours(10, 9, 17)).toBe(true);
      });

      it('should return true at range start', () => {
        expect(isInQuietHours(9, 9, 17)).toBe(true);
      });

      it('should return false at range end', () => {
        expect(isInQuietHours(17, 9, 17)).toBe(false);
      });

      it('should return false before range', () => {
        expect(isInQuietHours(8, 9, 17)).toBe(false);
      });

      it('should return false after range', () => {
        expect(isInQuietHours(18, 9, 17)).toBe(false);
      });
    });

    describe('wrap-around range (e.g., 22:00-07:00)', () => {
      it('should return true when hour is after start', () => {
        expect(isInQuietHours(23, 22, 7)).toBe(true);
      });

      it('should return true at start', () => {
        expect(isInQuietHours(22, 22, 7)).toBe(true);
      });

      it('should return true when hour is before end', () => {
        expect(isInQuietHours(5, 22, 7)).toBe(true);
      });

      it('should return false at end', () => {
        expect(isInQuietHours(7, 22, 7)).toBe(false);
      });

      it('should return false during daytime', () => {
        expect(isInQuietHours(12, 22, 7)).toBe(false);
      });

      it('should return true at midnight', () => {
        expect(isInQuietHours(0, 22, 7)).toBe(true);
      });
    });

    describe('edge cases', () => {
      it('should handle same start and end (empty range)', () => {
        expect(isInQuietHours(10, 10, 10)).toBe(false);
      });

      it('should handle full day range start=0 end=24', () => {
        expect(isInQuietHours(12, 0, 24)).toBe(true);
        expect(isInQuietHours(0, 0, 24)).toBe(true);
      });
    });
  });
});

